350	// TestProviderConnectivityViaService runs a HealthCheck against the named
351	// harness and translates the result into a ProviderStatus. It is the
352	// production replacement for Runner.TestProviderConnectivity.
353	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
354		status := ProviderStatus{Reachable: false}
355		if ctx == nil {
356			ctx = context.Background()
357		}
358		if harnessName == "virtual" || harnessName == "agent" {
359			status.Reachable = true
360			status.CreditsOK = true
361			return status
362		}
363		svc, err := NewServiceFromWorkDir(workDir)
364		if err != nil {
365			status.Error = err.Error()
366			return status
367		}
368		if timeout > 0 {
369			var cancel context.CancelFunc
370			ctx, cancel = context.WithTimeout(ctx, timeout)
371			defer cancel()
372		}
373		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
374			errStr := strings.ToLower(err.Error())
375			status.Error = err.Error()
376			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
377				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
378				status.CreditsOK = false
379			}
380			return status
381		}
382		status.Reachable = true
383		status.CreditsOK = true
384		return status
385	}
